  1	import React, { Dispatch, FC, SetStateAction, useEffect, useMemo, useRef } from 'react';
  2	
  3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  4	import FormGroupHelperText from '@kubevirt-utils/components/FormGroupHelperText/FormGroupHelperText';
  5	import Loading from '@kubevirt-utils/components/Loading/Loading';
  6	import SelectTypeahead from '@kubevirt-utils/components/SelectTypeahead/SelectTypeahead';
  7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  8	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
  9	import { getNetworks } from '@kubevirt-utils/resources/vm';
 10	import { interfacesTypes } from '@kubevirt-utils/resources/vm/utils/network/constants';
 11	import { FormGroup, Label, ValidatedOptions } from '@patternfly/react-core';
 12	
 13	import { getNadType, networkNameStartWithPod, podNetworkExists } from '../../utils/helpers';
 14	import useNADsData from '../hooks/useNADsData';
 15	
 16	import NetworkSelectHelperPopover from './components/NetworkSelectHelperPopover/NetworkSelectHelperPopover';
 17	
 18	type NetworkInterfaceNetworkSelectProps = {
 19	  editInitValueNetworkName?: string | undefined;
 20	  isEditing?: boolean | undefined;
 21	  namespace?: string;
 22	  networkName: string;
 23	  setInterfaceType: Dispatch<SetStateAction<string>>;
 24	  setNetworkName: Dispatch<SetStateAction<string>>;
 25	  setSubmitDisabled: Dispatch<SetStateAction<boolean>>;
 26	  vm: V1VirtualMachine;
 27	};
 28	
 29	const NetworkInterfaceNetworkSelect: FC<NetworkInterfaceNetworkSelectProps> = ({
 30	  editInitValueNetworkName,
 31	  isEditing,
 32	  namespace,
 33	  networkName,
 34	  setInterfaceType,
 35	  setNetworkName,
 36	  setSubmitDisabled,
 37	  vm,
 38	}) => {
 39	  const { t } = useKubevirtTranslation();
 40	
 41	  const { loaded, loadError, nads } = useNADsData(vm?.metadata?.namespace || namespace);
 42	
 43	  const currentlyUsedNADsNames = useMemo(
 44	    () => getNetworks(vm)?.map((network) => network?.multus?.networkName),
 45	    [vm],
 46	  );
 47	
 48	  const filteredNADs = nads?.filter(
 49	    (nad) => !currentlyUsedNADsNames?.includes(`${getNamespace(nad)}/${getName(nad)}`),
 50	  );
 51	
 52	  const selectedFirstOnLoad = useRef(false);
 53	
 54	  const hasPodNetwork = useMemo(() => podNetworkExists(vm), [vm]);
 55	  const hasNads = useMemo(() => filteredNADs?.length > 0, [filteredNADs]);
 56	  const isPodNetworkingOptionExists =
 57	    !hasPodNetwork || (isEditing && networkNameStartWithPod(editInitValueNetworkName));
 58	
 59	  const canCreateNetworkInterface = useMemo(
 60	    () => hasNads || !hasPodNetwork,
 61	    [hasNads, hasPodNetwork],
 62	  );
 63	
 64	  const podNetworkingText = useMemo(() => t('Pod Networking'), [t]);
 65	
 66	  const networkOptions = useMemo(() => {
 67	    const options = filteredNADs?.map((nad) => {
 68	      const { name, namespace: nadNamespace, uid } = nad?.metadata;
 69	      const type = getNadType(nad);
 70	      const value = `${nadNamespace}/${name}`;
 71	      return {
 72	        children: (
 73	          <>
 74	            {value} <Label isCompact>{getNadType(nad)} Binding</Label>
 75	          </>
 76	        ),
 77	        key: uid,
 78	        type,
 79	        value,
 80	      };
 81	    });
 82	
 83	    if (isPodNetworkingOptionExists) {
 84	      options.unshift({
 85	        children: (
 86	          <>
 87	            {podNetworkingText} <Label isCompact>{interfacesTypes.masquerade} Binding</Label>
 88	          </>
 89	        ),
 90	        key: 'pod-networking',
 91	        type: interfacesTypes.masquerade,
 92	        value: podNetworkingText,
 93	      });
 94	    }
 95	    return options;
 96	  }, [isPodNetworkingOptionExists, filteredNADs, podNetworkingText]);
 97	
 98	  const validated =
 99	    canCreateNetworkInterface || isEditing ? ValidatedOptions.default : ValidatedOptions.error;
100	
101	  const handleChange = (value: string) => {
102	    setNetworkName(value);
103	    setInterfaceType(
104	      value === podNetworkingText
105	        ? interfacesTypes.masquerade
106	        : networkOptions.find((netOption) => value === netOption?.value)?.type,
107	    );
108	  };
109	
110	  // This useEffect is to handle the submit button and init value
111	  useEffect(() => {
112	    // if networkName exists, we have the option to create a NIC either with pod networking or by existing NAD
113	    if (networkName) {
114	      setSubmitDisabled(false);
115	      return;
116	    }
117	
118	    // if networkName is empty, and pod network exists we can create a NIC with existing NAD if there is one
119	    if (loaded && !loadError && !selectedFirstOnLoad.current) {
120	      setNetworkName(networkOptions?.[0]?.value);
121	      selectedFirstOnLoad.current = true;
122	
123	      return;
124	    }
125	
126	    // if no nads and pod network already exists, we can't create a NIC
127	    if (loaded && (loadError || !canCreateNetworkInterface)) {
128	      setSubmitDisabled(true);
129	      return;
130	    }
131	  }, [
132	    loadError,
133	    canCreateNetworkInterface,
134	    loaded,
135	    networkName,
136	    networkOptions,
137	    setNetworkName,
138	    setSubmitDisabled,
139	  ]);
140	
141	  return (
142	    <FormGroup
143	      fieldId="network-attachment-definition"
144	      isRequired
145	      label={t('Network')}
146	      labelHelp={<NetworkSelectHelperPopover />}
147	    >
148	      <div data-test-id="network-attachment-definition-select">
149	        {hasPodNetwork && !loaded ? (
150	          <Loading />
151	        ) : (
152	          <SelectTypeahead
153	            getCreateOption={(inputValue) => (
154	              <>
155	                {t(`Use "{{inputValue}}"`, { inputValue })}{' '}
156	                <Label isCompact>{interfacesTypes.bridge} Binding</Label>
157	              </>
158	            )}
159	            dataTestId="select-nad"
160	            initialOptions={networkOptions}
161	            isFullWidth
162	            placeholder={t('Select a NetworkAttachmentDefinitions')}
163	            selected={networkName}
164	            setSelected={handleChange}
165	          />
166	        )}
167	      </div>
168	      {loaded && validated === ValidatedOptions.error && (
169	        <FormGroupHelperText validated={validated}>
170	          {t(
171	            'No NetworkAttachmentDefinitions available. Contact your system administrator for additional support.',
172	          )}
173	        </FormGroupHelperText>
174	      )}
175	    </FormGroup>
176	  );
177	};
178	
179	export default NetworkInterfaceNetworkSelect;

